use std::collections::{HashMap, HashSet, VecDeque};

impl Solution {
    pub fn alien_order(words: Vec<String>) -> String {
        let mut adj: HashMap<u8, HashSet<u8>> = HashMap::new();
        let mut in_degree: HashMap<u8, i32> = HashMap::new();
        for w in &words {
            for &c in w.as_bytes() {
                adj.entry(c).or_insert_with(HashSet::new);
                in_degree.entry(c).or_insert(0);
            }
        }
        for i in 0..words.len() - 1 {
            let w1 = words[i].as_bytes();
            let w2 = words[i + 1].as_bytes();
            let min_len = w1.len().min(w2.len());
            if w1.len() > w2.len() && &w1[..min_len] == &w2[..min_len] {
                return String::new();
            }
            for j in 0..min_len {
                if w1[j] != w2[j] {
                    if adj.get_mut(&w1[j]).unwrap().insert(w2[j]) {
                        *in_degree.entry(w2[j]).or_insert(0) += 1;
                    }
                    break;
                }
            }
        }
        let mut queue: VecDeque<u8> = VecDeque::new();
        for (&c, &d) in &in_degree {
            if d == 0 {
                queue.push_back(c);
            }
        }
        let mut result = Vec::new();
        while let Some(c) = queue.pop_front() {
            result.push(c as char);
            if let Some(neighbors) = adj.get(&c) {
                for &nei in neighbors {
                    let entry = in_degree.entry(nei).or_insert(0);
                    *entry -= 1;
                    if *entry == 0 {
                        queue.push_back(nei);
                    }
                }
            }
        }
        if result.len() == in_degree.len() {
            result.iter().collect()
        } else {
            String::new()
        }
    }
}

