        let mut adj = vec![Vec::<usize>::new(); n];
        let mut in_degree = vec![0i32; n];
        for r in &relations {
            let (u, v) = (r[0] as usize - 1, r[1] as usize - 1);
            adj[u].push(v);
            in_degree[v] += 1;
        }
        let mut earliest = vec![0i32; n];
