impl Solution {
    pub fn longest_increasing_path(matrix: Vec<Vec<i32>>) -> i32 {
        if matrix.is_empty() {
            return 0;
        }
        let m = matrix.len();
        let n = matrix[0].len();
        let mut memo = vec![vec![0i32; n]; m];
        let dirs = [(0i32, 1i32), (0, -1), (1, 0), (-1, 0)];

        fn dfs(
            matrix: &Vec<Vec<i32>>,
            memo: &mut Vec<Vec<i32>>,
            dirs: &[(i32, i32); 4],
            i: usize,
            j: usize,
        ) -> i32 {
            if memo[i][j] != 0 {
                return memo[i][j];
            }
            let m = matrix.len();
            let n = matrix[0].len();
            let mut best = 1;
            for &(di, dj) in dirs {
                let ni = i as i32 + di;
                let nj = j as i32 + dj;
                if ni >= 0 && (ni as usize) < m && nj >= 0 && (nj as usize) < n {
                    let (ni, nj) = (ni as usize, nj as usize);
                    if matrix[ni][nj] > matrix[i][j] {
                        best = best.max(1 + dfs(matrix, memo, dirs, ni, nj));
                    }
                }
            }
            memo[i][j] = best;
            best
        }

        let mut max_len = 0;
        for i in 0..m {
            for j in 0..n {
                max_len = max_len.max(dfs(&matrix, &mut memo, &dirs, i, j));
            }
        }
        max_len
    }
}
